from flask import Flask, redirect, request, session, url_for, jsonify
import secrets
import hashlib
import base64
import requests
from urllib.parse import urlencode
import jwt
from functools import wraps

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

OIDC_CONFIG = {
    'client_id': 'your-client-id',
    'client_secret': 'your-client-secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'authorization_endpoint': 'https://your-idp.com/authorize',
    'token_endpoint': 'https://your-idp.com/token',
    'jwks_uri': 'https://your-idp.com/.well-known/jwks.json',
    'issuer': 'https://your-idp.com'
}

def generate_pkce_pair():
    code_verifier = base64.urlsafe_b64encode(secrets.token_bytes(32)).decode('utf-8').rstrip('=')
    code_challenge = base64.urlsafe_b64encode(
        hashlib.sha256(code_verifier.encode('utf-8')).digest()
    ).decode('utf-8').rstrip('=')
    return code_verifier, code_challenge

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/')
@login_required
def index():
    return jsonify({'message': 'Welcome to Admin Dashboard', 'user': session.get('user')})

@app.route('/login')
def login():
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    code_verifier, code_challenge = generate_pkce_pair()
    
    session['state'] = state
    session['nonce'] = nonce
    session['code_verifier'] = code_verifier
    
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': 'openid profile email',
        'response_type': 'code',
        'state': state,
        'nonce': nonce,
        'code_challenge': code_challenge,
        'code_challenge_method': 'S256'
    }
    
    auth_url = f"{OIDC_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error, 'description': request.args.get('error_description')}), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return jsonify({'error': 'Missing authorization code'}), 400
    
    if not state or state != session.get('state'):
        return jsonify({'error': 'Invalid state parameter - possible CSRF attack'}), 400
    
    code_verifier = session.get('code_verifier')
    expected_nonce = session.get('nonce')
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
        'code_verifier': code_verifier
    }
    
    try:
        token_response = requests.post(
            OIDC_CONFIG['token_endpoint'],
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'},
            timeout=10
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Token exchange failed', 'details': str(e)}), 500
    
    id_token = tokens.get('id_token')
    if not id_token:
        return jsonify({'error': 'No ID token received'}), 400
    
    try:
        jwks_response = requests.get(OIDC_CONFIG['jwks_uri'], timeout=10)
        jwks_response.raise_for_status()
        jwks = jwks_response.json()
        
        unverified_header = jwt.get_unverified_header(id_token)
        kid = unverified_header.get('kid')
        
        rsa_key = None
        for key in jwks.get('keys', []):
            if key.get('kid') == kid:
                rsa_key = {
                    'kty': key['kty'],
                    'kid': key['kid'],
                    'use': key['use'],
                    'n': key['n'],
                    'e': key['e']
                }
                break
        
        if not rsa_key:
            return jsonify({'error': 'Unable to find appropriate key'}), 400
        
        from jwt.algorithms import RSAAlgorithm
        public_key = RSAAlgorithm.from_jwk(rsa_key)
        
        claims = jwt.decode(
            id_token,
            public_key,
            algorithms=['RS256'],
            audience=OIDC_CONFIG['client_id'],
            issuer=OIDC_CONFIG['issuer']
        )
        
        if claims.get('nonce') != expected_nonce:
            return jsonify({'error': 'Invalid nonce - possible replay attack'}), 400
        
        session.pop('state', None)
        session.pop('nonce', None)
        session.pop('code_verifier', None)
        
        session['user'] = {
            'sub': claims.get('sub'),
            'email': claims.get('email'),
            'name': claims.get('name'),
            'preferred_username': claims.get('preferred_username')
        }
        session['id_token'] = id_token
        session['access_token'] = tokens.get('access_token')
        
        return redirect(url_for('index'))
        
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'ID token has expired'}), 400
    except jwt.InvalidTokenError as e:
        return jsonify({'error': 'Invalid ID token', 'details': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'Token validation failed', 'details': str(e)}), 500

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

